	if !validColumns[orderBy] {
		return nil, errors.New("invalid orderBy column: must be 'id', 'name', or 'price'")
	}

	// Validate sortDir
	sortDir = strings.ToUpper(sortDir)
	if sortDir != "ASC" && sortDir != "DESC" {
		return nil, errors.New("sortDir must be 'ASC' or 'DESC'")
	}

	// Use parameterized query to prevent SQL injection
	query := "SELECT id, name, price FROM products ORDER BY ? ?"

	rows, err := db.Query(query, orderBy, sortDir)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var products []Product
	for rows.Next() {
		var p Product
		err := rows.Scan(&p.ID, &p.Name, &p.Price)
		if err != nil {
			return nil, err
		}
		products = append(products, p)
	}

	if err = rows.Err(); err != nil {
		return nil, err
	}

	return products, nil
}

