import (
	"database/sql"
	"errors"
	"fmt"
)

type Product struct {
	ID    int
	Name  string
	Price float64
}

// ListProducts queries the database for products sorted by a specific column and direction.
func ListProducts(db *sql.DB, orderBy string, sortDir string) ([]Product, error) {
	// Validate orderBy column to prevent SQL injection
	validColumns := map[string]bool{
		"id":    true,
		"name":  true,
		"price": true,
	}

	if !validColumns[orderBy] {
		return nil, fmt.Errorf("invalid orderBy column: %s", orderBy)
	}

	// Validate sort direction
	sortDir = sanitizeSortDir(sortDir)
	if sortDir == "" {
		return nil, errors.New("invalid sortDir: must be ASC or DESC")
	}

	// Construct SQL query with validated parameters
	query := fmt.Sprintf("SELECT id, name, price FROM products ORDER BY %s %s", orderBy, sortDir)

	rows, err := db.Query(query)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var products []Product

	for rows.Next() {
		var product Product
		err := rows.Scan(&product.ID, &product.Name, &product.Price)
		if err != nil {
			return nil, err
		}
		products = append(products, product)
	}

	if err = rows.Err(); err != nil {
		return nil, err
	}

	return products, nil
}

// sanitizeSortDir ensures sort direction is either ASC or DESC
func sanitizeSortDir(dir string) string {
	switch dir {
	case "ASC", "asc":
		return "ASC"
	case "DESC", "desc":
		return "DESC"
	default:
		return ""
	}
}

